import React, { useState, useEffect } from 'react';
import { Routes, Route } from 'react-router-dom';
import Sidebar from '../Layout/Sidebar';
import Navbar from '../Layout/Navbar';
import api from '../../services/api';
import { useAuth } from '../../context/AuthContext';
import {
  Calendar,
  Bell,
  TrendingUp,
  Users,
  CheckCircle,
  AlertCircle
} from 'lucide-react';
import NoticeBoard from './NoticeBoard';
import AttendanceTracker from './AttendanceTracker';
import ScoresSection from './ScoresSection';
import OpportunityFeed from './OpportunityFeed';
import StudentDirectory from './StudentDirectory';
import TeamBoard from './TeamBoard';
import ClubEvents from './ClubEvents';
import StudentProfile from './StudentProfile';

const StudentDashboard = () => {
  const { user } = useAuth();
  const [dashboardData, setDashboardData] = useState({
    attendance: { percentage: 85 },
    scores: { minor1: 75, minor2: 80 },
    recentNotices: []
  });

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const response = await api.get(`/students/${user.studentId}/dashboard`);
      if (response.data.success) {
        setDashboardData(response.data.data);
      }
    } catch (error) {
      console.error('Error fetching dashboard:', error);
    }
  };

  const stats = [
    {
      title: 'Attendance',
      value: `${dashboardData.attendance?.percentage || 0}%`,
      icon: Calendar,
      color: 'blue'
    },
    {
      title: 'Minor 1 Score',
      value: `${dashboardData.scores?.minor1 || 0}/100`,
      icon: TrendingUp,
      color: 'green'
    },
    {
      title: 'Minor 2 Score',
      value: `${dashboardData.scores?.minor2 || 0}/100`,
      icon: TrendingUp,
      color: 'purple'
    },
    {
      title: 'Recent Notices',
      value: dashboardData.recentNotices?.length || 0,
      icon: Bell,
      color: 'orange'
    }
  ];

  const DashboardHome = () => (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, index) => {
          const Icon = stat.icon;
          return (
            <div key={index} className="card">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-gray-500 text-sm">{stat.title}</p>
                  <p className="text-2xl font-bold text-gray-800 mt-1">
                    {stat.value}
                  </p>
                </div>
                <div className={`w-12 h-12 bg-${stat.color}-100 rounded-lg flex items-center justify-center`}>
                  <Icon className={`w-6 h-6 text-${stat.color}-600`} />
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {dashboardData.attendance?.percentage < 75 && (
        <div className="bg-red-50 border border-red-200 rounded-lg p-4 flex items-start gap-3">
          <AlertCircle className="w-5 h-5 text-red-600 mt-0.5" />
          <div>
            <h3 className="font-semibold text-red-800">Low Attendance Alert!</h3>
            <p className="text-red-700 text-sm">
              Your attendance is {dashboardData.attendance?.percentage}%. Please maintain at least 75% to be eligible for exams.
            </p>
          </div>
        </div>
      )}

      <div className="card">
        <h2 className="text-lg font-semibold text-gray-800 mb-4">Recent Notices</h2>
        <div className="space-y-3">
          {dashboardData.recentNotices?.slice(0, 3).map((notice) => (
            <div key={notice.id} className="p-3 bg-gray-50 rounded-lg">
              <h3 className="font-medium text-gray-800">{notice.title}</h3>
              <p className="text-sm text-gray-600 mt-1">{notice.description}</p>
              {notice.deadline && (
                <p className="text-xs text-red-600 mt-2">
                  Deadline: {new Date(notice.deadline).toLocaleDateString()}
                </p>
              )}
            </div>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="card">
          <h2 className="text-lg font-semibold text-gray-800 mb-4">Upcoming Deadlines</h2>
          <div className="space-y-2">
            <div className="flex items-center justify-between p-2 hover:bg-gray-50 rounded">
              <span>Assignment Submission</span>
              <span className="text-sm text-red-600">Due in 2 days</span>
            </div>
            <div className="flex items-center justify-between p-2 hover:bg-gray-50 rounded">
              <span>Project Presentation</span>
              <span className="text-sm text-orange-600">Due in 5 days</span>
            </div>
          </div>
        </div>
        <div className="card">
          <h2 className="text-lg font-semibold text-gray-800 mb-4">Recent Achievements</h2>
          <div className="space-y-2">
            <div className="flex items-center gap-2">
              <CheckCircle className="w-4 h-4 text-green-600" />
              <span className="text-sm">Completed Python Course</span>
            </div>
            <div className="flex items-center gap-2">
              <CheckCircle className="w-4 h-4 text-green-600" />
              <span className="text-sm">Joined Coding Club</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="flex h-screen bg-gray-50">
      <Sidebar role="student" />
      <div className="flex-1 ml-64">
        <Navbar />
        <main className="p-6">
          <Routes>
            <Route path="/" element={<DashboardHome />} />
            <Route path="/notices" element={<NoticeBoard />} />
            <Route path="/attendance" element={<AttendanceTracker />} />
            <Route path="/scores" element={<ScoresSection />} />
            <Route path="/opportunities" element={<OpportunityFeed />} />
            <Route path="/directory" element={<StudentDirectory />} />
            <Route path="/teams" element={<TeamBoard />} />
            <Route path="/events" element={<ClubEvents />} />
            <Route path="/profile" element={<StudentProfile />} />
          </Routes>
        </main>
      </div>
    </div>
  );
};

export default StudentDashboard;
